data.content:
MSTest **does** have comparison assertions — here's what to use:

```csharp
Assert.IsGreaterThan(lowerBound, actual);
Assert.IsLessThan(upperBound, actual);
Assert.IsInRange(actual, low, high);
```

For your `ScoreCalculator`, here's how boundary tests would look:

```csharp
[TestClass]
public sealed class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    [TestMethod]
    [DataRow(7, 10, 70.0)]
    [DataRow(10, 10, 100.0)]
    [DataRow(0, 5, 0.0)]
    public void CalculatePercentage_ValidInputs_ReturnsExpected(int correct, int total, double expected)
    {
        Assert.AreEqual(expected, _calc.CalculatePercentage(correct, total));
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsInValidRange()
    {
        var result = _calc.CalculatePercentage(3, 7);

        Assert.IsInRange(result, 0.0, 100.0);
        Assert.IsGreaterThan(0.0, result); // result > 0
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsExactly<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(0, 0));
    }

    [TestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.99, "B")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.99, "F")]
    public void GetGrade_AtBoundary_ReturnsCorrectGrade(double percentage, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(percentage));
    }

    [TestMethod]
    public void NormalizeScore_ExceedsMax_CapsAt100()
    {
        var result = _calc.NormalizeScore(150, 100);

        Assert.AreEqual(100.0, result);
        Assert.IsLessThan(100.01, result); // doesn't exceed cap
    }

    [TestMethod]
    public void NormalizeScore_ValidInput_ReturnsInRange()
    {
        var result = _calc.NormalizeScore(50, 200);

        Assert.IsInRange(result, 0.0, 100.0);
    }
}
```

**Key points:**
- `Assert.IsGreaterThan(bound, actual)` — actual must be > bound
- `Assert.IsLessThan(bound, actual)` — actual must be < bound
- `Assert.IsInRange(actual, low, high)` — actual must be in [low, high]

These give clearer failure messages than `Assert.IsTrue(x > 0)`. They require **MSTest 3.x+**.
